  private buildPdfHeaderLogo(businessName: string): string {
    if (this.pdfUseImageHeader) {
      return `<img class="brand-logo" src="${this.brandLogoDataUri}" alt="${businessName}">`;
    }

    return `<div class="brand-wordmark">${businessName}</div>`;
  }

  private buildPdfWatermark(): string {
    if (!this.pdfIncludeWatermarks) return '';
    return `<img class="watermark-symbol" src="${this.brandSymbolDataUri}" alt="">`;
  }

  private buildPdfPage(cardMarkup: string, businessName: string, pageClass = ''): string {
    return `
      <main class="pdf-page ${pageClass}">
        <header class="brand-hero">
          ${this.buildPdfHeaderLogo(businessName)}
          <div class="ornament"><span></span></div>
        </header>

        <section class="single-card-wrap">
          ${cardMarkup}
        </section>

        <footer class="footer">@praticita_doces_e_salgados</footer>
      </main>
    `;
  }

